// WEDA — Frontend App // Onboarding form+filterable vendor grid+shortlist drawer const vendors=[{id:1,name:"ShutterLoom Weddings",category:"photography",tier:"mid",city:"Ahmedabad",blurb:"Candid and portrait photography across all five ceremonies.",},{id:2,name:"Mogra & Gold Decor Studio",category:"decor",tier:"premium",city:"Vadodara",blurb:"Luxury floral mandap installations and stage design.",},{id:3,name:"Rasoi Ritual Caterers",category:"catering",tier:"economy",city:"Surat",blurb:"Authentic Gujarati thali,live chaat,and chaas stations.",},{id:4,name:"Apsara Bridal Makeup",category:"makeup",tier:"mid",city:"Ahmedabad",blurb:"Airbrush bridal looks for all skin tones and ceremony types.",},{id:5,name:"Riyaaz Film House",category:"photography",tier:"premium",city:"Ahmedabad",blurb:"Cinematic wedding films with drone aerial coverage.",},{id:6,name:"Paan Leaf Décor Co.",category:"decor",tier:"mid",city:"Surat",blurb:"Fresh floral and eco-friendly installations for every event.",},];// ─── State ─── let shortlist=[];// ─── Elements ─── const form=document.getElementById("onboarding-form");const statusEl=document.getElementById("onboarding-status");const budgetInput=document.getElementById("budget");const budgetBadge=document.getElementById("budget-badge");const listEl=document.getElementById("vendor-list");const categoryEl=document.getElementById("category");const tierEl=document.getElementById("budget-range");const filterTally=document.getElementById("filter-tally");const shortlistToggle=document.getElementById("shortlist-toggle");const shortlistCount=document.getElementById("shortlist-count");const drawerPanel=document.getElementById("shortlist-panel");const drawerBackdrop=document.getElementById("drawer-backdrop");const drawerClose=document.getElementById("shortlist-close");const drawerItems=document.getElementById("shortlist-items");const drawerEmpty=document.getElementById("drawer-empty");// ─── Vendor rendering ─── function renderVendors(){const cat=categoryEl.value;const tier=tierEl.value;const filtered=vendors.filter((v)=>(cat==="all" || v.category===cat)&&(tier==="all" || v.tier===tier));filterTally.textContent=filtered.length > 0 ? `${filtered.length}vendor${filtered.length !==1 ? "s":""}found`:"";listEl.innerHTML="";if(filtered.length===0){const li=document.createElement("li");li.className="vendor-card vendor-card--empty";li.textContent="No vendors match the current filters.";listEl.append(li);return}filtered.forEach((vendor,i)=>{const saved=shortlist.some((s)=> s.id===vendor.id);const li=document.createElement("li");li.className=`vendor-card vendor-tier--${vendor.tier}`;li.style.animationDelay=`${i * 0.07}s`;li.innerHTML=` <span class="vendor-badge">${vendor.tier}</span> <h3 class="vendor-name">${vendor.name}</h3> <div class="vendor-tags"> <span class="vendor-tag">${vendor.category}</span> <span class="vendor-tag">${vendor.city}</span> </div> <p class="vendor-blurb">${vendor.blurb}</p> <div class="vendor-actions"> <button class="btn-shortlist${saved ? " is-saved":""}" data-id="${vendor.id}" aria-pressed="${saved}" >${saved ? "✓ Shortlisted":"Shortlist"}</button> </div> `;listEl.append(li)})}// ─── Shortlist toggle(delegated)─── listEl.addEventListener("click",(e)=>{const btn=e.target.closest(".btn-shortlist");if(!btn)return;const id=Number(btn.dataset.id);const vendor=vendors.find((v)=> v.id===id);if(!vendor)return;const idx=shortlist.findIndex((s)=> s.id===id);if(idx >=0){shortlist.splice(idx,1)}else{shortlist.push(vendor)}renderVendors();renderDrawerItems();updateCount()});// ─── Shortlist drawer items ─── function renderDrawerItems(){drawerItems.innerHTML="";const hasItems=shortlist.length > 0;drawerEmpty.classList.toggle("is-hidden",hasItems);shortlist.forEach((vendor)=>{const li=document.createElement("li");li.className="drawer-item";li.innerHTML=` <span class="drawer-item-name">${vendor.name}</span> <span class="drawer-item-meta">${vendor.category}· ${vendor.city}· ${vendor.tier}</span> <button class="drawer-item-remove" data-id="${vendor.id}" aria-label="Remove ${vendor.name}from shortlist"> Remove </button> `;drawerItems.append(li)})}drawerItems.addEventListener("click",(e)=>{const btn=e.target.closest(".drawer-item-remove");if(!btn)return;const id=Number(btn.dataset.id);shortlist=shortlist.filter((s)=> s.id !==id);renderDrawerItems();renderVendors();updateCount()});function updateCount(){const n=shortlist.length;shortlistCount.textContent=n;shortlistCount.setAttribute("aria-label",`${n}saved`);shortlistToggle.setAttribute("aria-label",`Open shortlist,${n}vendor${n !==1 ? "s":""}saved`)}// ─── Drawer open / close ─── function openDrawer(){drawerPanel.classList.add("is-open");drawerPanel.setAttribute("aria-hidden","false");drawerBackdrop.classList.add("is-open");drawerBackdrop.setAttribute("aria-hidden","false");shortlistToggle.setAttribute("aria-expanded","true");document.body.style.overflow="hidden";drawerClose.focus()}function closeDrawer(){drawerPanel.classList.remove("is-open");drawerPanel.setAttribute("aria-hidden","true");drawerBackdrop.classList.remove("is-open");drawerBackdrop.setAttribute("aria-hidden","true");shortlistToggle.setAttribute("aria-expanded","false");document.body.style.overflow="";shortlistToggle.focus()}shortlistToggle.addEventListener("click",openDrawer);drawerClose.addEventListener("click",closeDrawer);drawerBackdrop.addEventListener("click",closeDrawer);document.addEventListener("keydown",(e)=>{if(e.key==="Escape" && drawerPanel.classList.contains("is-open")){closeDrawer()}});// ─── Budget badge ─── budgetInput.addEventListener("input",()=>{const val=Number(budgetInput.value);if(!val){budgetBadge.textContent="";return}if(val >=10_000_000)budgetBadge.textContent=`₹${(val / 10_000_000).toFixed(1)}Cr`;else if(val >=100_000)budgetBadge.textContent=`₹${(val / 100_000).toFixed(1)}L`;else budgetBadge.textContent=`₹${val.toLocaleString("en-IN")}`});// ─── Onboarding form ─── form.addEventListener("submit",(e)=>{e.preventDefault();if(!form.reportValidity()){statusEl.textContent="Please fill in all required fields.";return}statusEl.textContent="Preferences saved. Vendors are now personalized for you.";document.getElementById("discovery").scrollIntoView({behavior:"smooth",block:"start"})});// ─── Filter listeners ─── categoryEl.addEventListener("change",renderVendors);tierEl.addEventListener("change",renderVendors);// ─── Init ─── renderVendors();renderDrawerItems();